import{_ as a,o as r,c as o,a2 as l}from"./chunks/framework.DnrXFDHb.js";const c=JSON.parse('{"title":"被動元件產業總覽","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/被動元件研究/被動元件_產業總覽.md","filePath":"Deep32Q知識庫/產業洞察/被動元件研究/被動元件_產業總覽.md"}'),i={name:"Deep32Q知識庫/產業洞察/被動元件研究/被動元件_產業總覽.md"};function e(n,t,s,h,d,g){return r(),o("div",null,[...t[0]||(t[0]=[l('<h1 id="被動元件產業總覽" tabindex="-1">被動元件產業總覽 <a class="header-anchor" href="#被動元件產業總覽" aria-label="Permalink to &quot;被動元件產業總覽&quot;">​</a></h1><p><strong>更新日期：2026-05-12</strong><strong>產出者：Dr.32 知識管家（subagent）</strong></p><hr><h2 id="_1-產業定義" tabindex="-1">1. 產業定義 <a class="header-anchor" href="#_1-產業定義" aria-label="Permalink to &quot;1. 產業定義&quot;">​</a></h2><p>被動元件（Passive Components）是指不需要外部電源即可運作的電子元件，主要功能是儲存能量、濾波、耦合、阻抗匹配等。三大核心分類：</p><table tabindex="0"><thead><tr><th>分類</th><th>英文</th><th>主要功能</th></tr></thead><tbody><tr><td><strong>MLCC</strong>（積層陶瓷電容）</td><td>Multilayer Ceramic Capacitor</td><td>儲能、濾波、去耦</td></tr><tr><td><strong>晶片電阻</strong>（Chip Resistor）</td><td>Chip Resistor</td><td>限流、分壓、阻抗匹配</td></tr><tr><td><strong>電感</strong>（Inductor）</td><td>Inductor</td><td>儲能、濾波、DC-DC轉換</td></tr></tbody></table><p>此外還包含：鉭電容（Tantalum）、保護元件（PTC/NTC/PPTC）、鋁質電解電容等。</p><hr><h2 id="_2-全球市場規模" tabindex="-1">2. 全球市場規模 <a class="header-anchor" href="#_2-全球市場規模" aria-label="Permalink to &quot;2. 全球市場規模&quot;">​</a></h2><h3 id="總體市場" tabindex="-1">總體市場 <a class="header-anchor" href="#總體市場" aria-label="Permalink to &quot;總體市場&quot;">​</a></h3><ul><li><strong>2025年全球被動元件市場</strong>：約 <strong>3,560 億美元</strong>（含 MLCC + 電阻 + 電感 + 其他被動元件）</li><li><strong>2026年預估</strong>：約 <strong>3,750–4,150 億美元</strong>（+5~8% YoY）</li><li><strong>2030年展望</strong>：部分研究機構預估可達 5,000–743 億美元（含互連元件）</li></ul><blockquote><p>註：不同研究機構對「被動元件」定義範圍不同，部分包含互連元件（interconnecting components）可達 200+ 億美元。本報告採用狹義被動元件定義（不含互連）。</p></blockquote><h3 id="三大細分市場" tabindex="-1">三大細分市場 <a class="header-anchor" href="#三大細分市場" aria-label="Permalink to &quot;三大細分市場&quot;">​</a></h3><table tabindex="0"><thead><tr><th>細分類別</th><th>2025 規模</th><th>2026 預估</th><th>CAGR (2025-30)</th></tr></thead><tbody><tr><td><strong>MLCC</strong></td><td>$164–237 億</td><td>$176–263 億</td><td>7~11%</td></tr><tr><td><strong>晶片電阻</strong></td><td>$108.5 億</td><td>$112 億</td><td>3~6%</td></tr><tr><td><strong>電感</strong></td><td>$84.2 億</td><td>$89.1 億</td><td>5~8%</td></tr></tbody></table><p><strong>MLCC</strong> 佔被動元件市場最大份額（約 45-60%），是 AI 伺服器需求爆發的最大受惠者。</p><hr><h2 id="_3-台灣產業產值" tabindex="-1">3. 台灣產業產值 <a class="header-anchor" href="#_3-台灣產業產值" aria-label="Permalink to &quot;3. 台灣產業產值&quot;">​</a></h2><ul><li><strong>2025年台灣被動元件產值</strong>：約 <strong>2,571 億台幣</strong>（+6.3% YoY）</li><li><strong>全球市佔率</strong>：台灣在全球被動元件供應鏈中佔有重要地位，尤其在 MLCC、晶片電阻、電感領域</li><li><strong>亞太地區</strong>：佔全球被動元件市場 47%+（2026年預估），台灣是核心製造基地</li></ul><h3 id="台灣被動元件產業特色" tabindex="-1">台灣被動元件產業特色 <a class="header-anchor" href="#台灣被動元件產業特色" aria-label="Permalink to &quot;台灣被動元件產業特色&quot;">​</a></h3><ul><li><strong>完整供應鏈</strong>：從上游陶瓷粉末、導電漿料到中游製造、下游應用，台灣具備完整產能</li><li><strong>AI 供應鏈整合</strong>：國巨集團（Yageo Group）整合 MLCC、電阻、鉭電、電感，提供一站式解決方案</li><li><strong>日系轉單效應</strong>：日商產能轉向高階 AI 產品，中低階市場由台廠承接</li></ul><hr><h2 id="_4-核心成長驅動因子" tabindex="-1">4. 核心成長驅動因子 <a class="header-anchor" href="#_4-核心成長驅動因子" aria-label="Permalink to &quot;4. 核心成長驅動因子&quot;">​</a></h2><h3 id="🔴-ai-伺服器需求——三重爆炸" tabindex="-1">🔴 AI 伺服器需求——三重爆炸 <a class="header-anchor" href="#🔴-ai-伺服器需求——三重爆炸" aria-label="Permalink to &quot;🔴 AI 伺服器需求——三重爆炸&quot;">​</a></h3><h4 id="_1-數量爆炸" tabindex="-1">（1）數量爆炸 <a class="header-anchor" href="#_1-數量爆炸" aria-label="Permalink to &quot;（1）數量爆炸&quot;">​</a></h4><ul><li>傳統 AI 伺服器 MLCC 用量：3,000–5,000 顆</li><li><strong>GB200 NVL72 機櫃</strong>：需約 <strong>441,000 顆 MLCC</strong>（是傳統 AI 伺服器的 10-21 倍）</li><li><strong>2026年 AI 伺服器 MLCC 需求</strong>：預估 726 億顆</li><li><strong>2027年預估</strong>：1,367 億顆</li></ul><h4 id="_2-規格爆炸" tabindex="-1">（2）規格爆炸 <a class="header-anchor" href="#_2-規格爆炸" aria-label="Permalink to &quot;（2）規格爆炸&quot;">​</a></h4><ul><li>從 H100 → Rubin Ultra，機櫃 MLCC 數量增 90 倍</li><li>高容值（100μF+）、高電壓（&gt;1kV，HVDC 架構）、低 ESR</li><li>800V HVDC 架構推升高壓 MLCC 需求</li></ul><h4 id="_3-漲價循環" tabindex="-1">（3）漲價循環 <a class="header-anchor" href="#_3-漲價循環" aria-label="Permalink to &quot;（3）漲價循環&quot;">​</a></h4><ul><li>村田、三星電機稼動率 &gt;90%</li><li>高階 MLCC 漲價 15-35%</li><li>國巨三波漲價（磁珠、鉭電、電阻）</li></ul><h3 id="🟡-車用電子" tabindex="-1">🟡 車用電子 <a class="header-anchor" href="#🟡-車用電子" aria-label="Permalink to &quot;🟡 車用電子&quot;">​</a></h3><ul><li>每台 EV 使用的 MLCC 數量遠高於燃油車（約 5-10 倍）</li><li>ADAS 系統增加保護元件需求</li><li>電動車電感、鋁質電容需求成長</li></ul><h3 id="🟢-5g-6g-通訊基礎建設" tabindex="-1">🟢 5G/6G 通訊基礎建設 <a class="header-anchor" href="#🟢-5g-6g-通訊基礎建設" aria-label="Permalink to &quot;🟢 5G/6G 通訊基礎建設&quot;">​</a></h3><ul><li>5G 基地台需要大量高頻 MLCC、電感、保護元件</li><li>6G 研發推進更高頻元件需求</li></ul><h3 id="🔵-低軌衛星" tabindex="-1">🔵 低軌衛星 <a class="header-anchor" href="#🔵-低軌衛星" aria-label="Permalink to &quot;🔵 低軌衛星&quot;">​</a></h3><ul><li>太空級高可靠度被動元件需求</li><li>信昌電、禾伸堂等台廠已切入供應鏈</li></ul><hr><h2 id="_5-台灣產業地位與競爭優勢" tabindex="-1">5. 台灣產業地位與競爭優勢 <a class="header-anchor" href="#_5-台灣產業地位與競爭優勢" aria-label="Permalink to &quot;5. 台灣產業地位與競爭優勢&quot;">​</a></h2><h3 id="全球競爭力" tabindex="-1">全球競爭力 <a class="header-anchor" href="#全球競爭力" aria-label="Permalink to &quot;全球競爭力&quot;">​</a></h3><ul><li><strong>國巨（Yageo）</strong>：全球第一大被動元件供應商，MLCC + 電阻 + 鉭電三合一</li><li><strong>華新科（Walsin）</strong>：全球前五 MLCC 廠，銅電極技術領先</li><li><strong>臺慶科</strong>：TLVR 電感打入 AI 電源，非日系首選</li><li><strong>光頡</strong>：薄膜電感/電阻利基市場，AI 佔比快速提升</li></ul><h3 id="競爭優勢" tabindex="-1">競爭優勢 <a class="header-anchor" href="#競爭優勢" aria-label="Permalink to &quot;競爭優勢&quot;">​</a></h3><ol><li><strong>完整供應鏈</strong>：上游材料（信昌電陶瓷粉末、九豪基板）到中游製造</li><li><strong>AI 供應鏈整合</strong>：國巨集團跨產品線協同效應</li><li><strong>非中國產能</strong>：地緣政治下，台廠成為 CSP 首選</li><li><strong>技術創新</strong>：銅電極、TLVR、高壓 MLCC 等技術領先</li></ol><hr><h2 id="📚-資料來源" tabindex="-1">📚 資料來源 <a class="header-anchor" href="#📚-資料來源" aria-label="Permalink to &quot;📚 資料來源&quot;">​</a></h2><ol><li><strong>Mordor Intelligence</strong> (2026-05): Global Passive Electronic Components Market Report</li><li><strong>Grand View Research</strong> (2026-05): MLCC Market Analysis</li><li><strong>Fortune Business Insights</strong> (2026-05): Passive Electronic Components Market</li><li><strong>TrendForce</strong> (2026-03): 國巨鉭電漲價、村田 AI 伺服器模組</li><li><strong>Digitimes</strong> (2026-03): Yageo tantalum capacitor price increase</li><li><strong>IEK (工研院)</strong>: 台灣被動元件產值統計</li><li><strong>StatementDog / StockAnalysis</strong>: 國巨 2025-2026 財務數據</li><li><strong>Fugle / Cmoney</strong>: 光頡、華新科、禾伸堂法說會摘要</li><li><strong>CTEE / ChinaTimes</strong>: 臺慶科、聚鼎、興勤相關報導</li><li><strong>Passive-Components.eu</strong>: 全球被動元件產業新聞彙整</li></ol>',44)])])}const C=a(i,[["render",e]]);export{c as __pageData,C as default};
